import React from 'react';
import { useChat } from '../context/ChatContext';
import './UserList.css';

const UserList = ({ users }) => {
  const { selectedUser, setSelectedUser, messages } = useChat();

  const getUnreadCount = (userId) => {
    const userMessages = messages[userId] || [];
    return userMessages.filter(m => m.received && !m.read).length;
  };

  return (
    <div className="user-list">
      {users.length === 0 ? (
        <p className="no-users">No users online</p>
      ) : (
        users.map(user => (
          <div
            key={user._id}
            className={`user-item ${selectedUser?._id === user._id ? 'selected' : ''}`}
            onClick={() => setSelectedUser(user)}
          >
            <div className="user-avatar">
              {user.nickname.charAt(0).toUpperCase()}
            </div>
            <div className="user-details">
              <span className="user-name">{user.nickname}</span>
              <span className={`user-gender-badge ${user.gender?.toLowerCase()}`}>
                {user.gender}
              </span>
            </div>
            {getUnreadCount(user._id) > 0 && (
              <span className="unread-badge">{getUnreadCount(user._id)}</span>
            )}
          </div>
        ))
      )}
    </div>
  );
};

export default UserList;
